#include <stdio.h>
int main() {
    int n, m, t, d, i, j;
    int a[100005];
    scanf("%d", &n);
    for (i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    scanf("%d", &m);
    for (i = 0; i < m; i++) {
        scanf("%d %d", &t, &d);
        int ans = -1;
        for (j = 0; j < n; j++) {
            int k = j;
            while (k < n && a[k] + d >= a[k+1]) {
                k++;
            }
            if (k < n && a[k] > t) {
                if (a[j] <= t) {
                    ans = j + 1;
                    break;
                }
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

